   356→export async function aiFeatureExtractionStage(
   357→  email: EmailMessage,
   358→  session: ClassificationSession,
   359→  result: ClassificationResult,
   360→  config: AIFeatureExtractionConfig
   361→): Promise<void> {
   362→  // ... validation logic ...
