   397→#### 5. MockAIClient (Test Implementation)
   398→
   399→**File**: `packages/email-processor/tests/helpers/mock-ai-client.ts`
   400→
   401→```typescript
   402→import type { AIClient, ChatCompletionParams, ChatCompletionResponse } from '@gmail-automation/classification-engine';
   403→
   404→/**
   405→ * Mock AI client for integration tests
   406→ *
   407→ * Provides deterministic responses without external API calls.
   408→ * Intelligently returns different responses based on prompt content.
   409→ */
   410→export class MockAIClient implements AIClient {
   411→  private callCount = 0;
   412→
   413→  async chatComplete(params: ChatCompletionParams): Promise<ChatCompletionResponse> {
   414→    this.callCount++;
   415→
   416→    // Determine which response to return based on prompt content
   417→    const userMessage = params.messages.find((m) => m.role === 'user')?.content || '';
   418→
   419→    // Feature extraction prompt detection
   420→    if (
   421→      userMessage.includes('feature') ||
   422→      userMessage.includes('semantic') ||
   423→      userMessage.includes('extract') ||
   424→      userMessage.includes('enhancement')
   425→    ) {
   426→      return this.createFeatureExtractionResponse();
   427→    }
   428→
   429→    // Classification prompt detection
   430→    return this.createClassificationResponse();
   431→  }
   432→
   433→  /**
   434→   * Mock feature extraction response
   435→   * Matches FeatureExtractionData interface exactly
   436→   */
   437→  private createFeatureExtractionResponse(): ChatCompletionResponse {
   438→    const responseData = {
   439→      semanticIntent: {
   440→        primaryPurpose: 'notification' as const,
   441→        actionRequired: 'view' as const,
   442→        urgencyLevel: 'low' as const,
   443→      },
   444→      categoryEnhancements: {
   445→        bills_receipts: {
   446→          applies: true,
   447→          confidenceBoost: 0.15,
   448→          evidence: {
   449→            quotedPhrases: ['Invoice', 'payment due'],
   450→            keywords: ['invoice', 'receipt', 'transaction'],
   451→            reasoning: 'Mock: Invoice-like content detected',
   452→          },
   453→        },
   454→        shopping_commerce: {
   455→          applies: true,
   456→          confidenceBoost: 0.05,
   457→          evidence: {
   458→            quotedPhrases: ['order', 'shipped'],
   459→            keywords: ['order', 'delivery', 'shipping'],
   460→            reasoning: 'Mock: Commercial transaction detected',
   461→          },
   462→        },
   463→      },
   464→    };
   465→
   466→    return {
   467→      choices: [
   468→        {
   469→          message: { content: JSON.stringify(responseData), role: 'assistant' },
   470→          finish_reason: 'stop',
   471→          index: 0,
   472→        },
   473→      ],
   474→      usage: {
   475→        total_tokens: 150,
   476→        prompt_tokens: 100,
   477→        completion_tokens: 50,
   478→      },
   479→      model: 'gpt-4o-mini-mock',
   480→      id: `mock-completion-${this.callCount}`,
   481→      created: Date.now(),
   482→    };
   483→  }
   484→
   485→  /**
   486→   * Mock classification response
   487→   * Matches FinalClassification interface exactly
   488→   */
   489→  private createClassificationResponse(): ChatCompletionResponse {
   490→    const responseData = {
   491→      primaryCategory: 'bills_receipts',
   492→      secondaryCategories: ['shopping_commerce'],
   493→      confidence: 0.85,
   494→      reasoning: 'Mock AI classification: Invoice detected based on transactional content',
   495→      categoryScores: {
   496→        bills_receipts: 0.85,
   497→        shopping_commerce: 0.65,
   498→        personal: 0.2,
   499→      },
   500→    };
   501→
   502→    return {
   503→      choices: [
   504→        {
   505→          message: { content: JSON.stringify(responseData), role: 'assistant' },
   506→          finish_reason: 'stop',
   507→          index: 0,
   508→        },
   509→      ],
   510→      usage: {
   511→        total_tokens: 150,
   512→        prompt_tokens: 100,
   513→        completion_tokens: 50,
   514→      },
   515→      model: 'gpt-4o-mini-mock',
   516→      id: `mock-completion-${this.callCount}`,
   517→      created: Date.now(),
   518→    };
   519→  }
   520→
   521→  /**
   522→   * Reset mock state (call in beforeEach)
   523→   */
   524→  reset(): void {
   525→    this.callCount = 0;
   526→  }
   527→
   528→  /**
   529→   * Get number of AI calls made (for test assertions)
