/**
 * Abstract interface for AI chat completion services
 *
 * Allows dependency injection and testing without module mocking.
 * Implementations: OpenAIClient (production), MockAIClient (tests)
 */
export interface AIClient {
  /**
   * Perform chat completion with AI model
   *
   * @param params - Chat completion parameters (model, messages, temperature, etc.)
   * @returns Response with AI-generated content and usage metrics
   */
  chatComplete(params: ChatCompletionParams): Promise<ChatCompletionResponse>;
}

/**
 * Parameters for AI chat completion
 * Provider-agnostic structure that works with OpenAI, Anthropic, local models, etc.
 */
export interface ChatCompletionParams {
  model: string;
  temperature: number;
  messages: Array<{
    role: 'system' | 'user' | 'assistant';
    content: string;
  }>;
  response_format?: {
    type: 'json_object' | 'json_schema';
    json_schema?: {
      name: string;
      description: string;
      schema: Record<string, unknown>;
      strict?: boolean;
    };
  };
}

/**
 * Response from AI chat completion
 * Normalized structure across different AI providers
 */
export interface ChatCompletionResponse {
  choices: Array<{
    message: {
      content: string | null;
      role?: string;
    };
    finish_reason?: string;
    index?: number;
  }>;
  usage?: {
    total_tokens?: number;
    prompt_tokens?: number;
    completion_tokens?: number;
  };
  model?: string;
  id?: string;
  created?: number;
}

