   496→    };
   497→  }
   498→
   499→  /**
   500→   * Extract configuration for hard assertions stage
   501→   */
   502→  private getHardAssertionConfig(): HardAssertionStageConfig {
   503→    const settings = this.config.processingConfig.settings;
   504→    return {
   505→      ...this.getBaseStageConfig(),
   506→      hardAssertionsSettings: settings.hardAssertions || { confidenceFloor: 1.0 },
   507→    };
   508→  }
