} from '../utils/template-utils';
import { FeatureExtractionData } from './ai-feature-extraction';

// Configuration interface for AI classification
export interface AIClassificationConfig {
  openai: {
    apiKey: string;
    model: string;
    temperature: number;
    responseFormat: 'json_schema' | 'json_object';
  };
  prompts: {
    systemPrompt: string[];
    userPrompt: string[];
  };
  classificationSchema: {
    name?: string;
    description?: string;
    schema: Record<string, unknown>;
    strict?: boolean;
  };
  skipConditions: {
    highConfidenceThreshold: number;
    skipReasons: string[];
  };
  retryPolicy: {
    maxRetries: number;
    backoffMs: number;
  };
}

// Final classification decision from AI
export interface FinalClassification {
  primaryCategory: string;
  secondaryCategories: string[];
  confidence: number;
  reasoning: string;
  categoryScores?: Record<string, number>;
}

// Enhancement calculation for explainability
export interface EnhancementCalculation {
  category: string;
  originalScore: number;
  confidenceBoost: number;
  enhancedScore: number;
  boostReason: string;
}

// AI routing decision details
export interface AIRoutingDecision {
  routedToAI: boolean;
  reason: string;
  confidenceScore?: number;
  threshold?: number;
  skipConditionsEvaluated: string[];
  decisionRationale: string;
}

// API usage tracking
export interface APIUsage {
  totalTokens: number;
  promptTokens?: number;
  completionTokens?: number;
}

// Complete explainability trace for the AI classification stage
export interface AIClassificationExplainabilityTrace {
  candidateScoresInput: Record<string, number>;
  extractedFeaturesInput: FeatureExtractionData;
  enhancementCalculations: EnhancementCalculation[];
  aiRoutingDecision: AIRoutingDecision;
  finalDecisionRationale: string;
  apiUsage?: APIUsage;
  processingSteps: string[];
}

// Complete stage result interface
export interface AIClassificationResult {
  finalClassification: FinalClassification;
  enhancedScores: Record<string, number>;
  aiInvoked: boolean;
  skipped: boolean;
  skipReason?: string;
  processingDurationMs: number;
  tokenUsage: number;
  apiCallCount: number;
  retryCount: number;
  validationErrors: string[];
  explainabilityTrace: AIClassificationExplainabilityTrace;
}

