import type { AIClient, ChatCompletionParams, ChatCompletionResponse } from '../../src/ai/ai-client';

/**
 * Simple mock AI client for unit tests
 *
 * Allows tests to control the response by setting mockResponse before calling the stage.
 */
export class MockAIClient implements AIClient {
  public mockResponse: ChatCompletionResponse | null = null;
  public lastParams: ChatCompletionParams | null = null;
  public callCount = 0;

  async chatComplete(params: ChatCompletionParams): Promise<ChatCompletionResponse> {
    this.lastParams = params;
    this.callCount++;

    if (!this.mockResponse) {
      throw new Error('MockAIClient: mockResponse not set. Call setMockResponse() before using the mock.');
    }

    return this.mockResponse;
  }

  setMockResponse(response: ChatCompletionResponse): void {
    this.mockResponse = response;
  }

  reset(): void {
    this.mockResponse = null;
    this.lastParams = null;
    this.callCount = 0;
  }
}

/**
 * Create a mock ChatCompletionResponse for testing
 */
export function createMockChatResponse(content: string, tokens = 150): ChatCompletionResponse {
  return {
    choices: [
      {
        message: {
          content,
          role: 'assistant',
        },
        finish_reason: 'stop',
        index: 0,
      },
    ],
    usage: {
      total_tokens: tokens,
      prompt_tokens: 100,
      completion_tokens: 50,
    },
    model: 'gpt-4o-mini-mock',
    id: 'mock-completion-id',
    created: Date.now(),
  };
}

