}

describe('EmailProcessor Integration Tests', () => {
  let gmailClient: MockGmailClient;
  let persistence: MockPersistenceService;
  let classificationOrchestrator: ClassificationOrchestrator;
  let emailProcessor: EmailProcessor;

  beforeEach(() => {
    // Create real components for integration testing
    gmailClient = new MockGmailClient();
    persistence = new MockPersistenceService();

    // Real ClassificationOrchestrator with real ClassificationPipeline
    // This is the key difference from unit tests - we're testing actual integration
    classificationOrchestrator = new ClassificationOrchestrator(validMinimalCategoryConfig);

    // EmailProcessor with real orchestrator
    emailProcessor = new EmailProcessor(
      gmailClient,
      classificationOrchestrator,
      persistence,
      validMinimalCategoryConfig.processingConfig
    );
  });

  afterEach(async () => {
    // Wait for any pending async operations to complete
    await new Promise((resolve) => setImmediate(resolve));
    // Clear all mocks to prevent test pollution
    jest.clearAllMocks();
  });

  describe('End-to-End Batch Processing (FR-001, FR-005, FR-008)', () => {
    test('should complete full workflow: fetch → classify → persist', async () => {
      // Setup: Create realistic email data
      const mockEmails = [
        createRealisticEmail('msg-001', 'Your Amazon order has shipped', 'shipment@amazon.com'),
        createRealisticEmail('msg-002', 'Weekly newsletter from TechCrunch', 'newsletter@techcrunch.com'),
      ];

      gmailClient.setMockEmails(mockEmails);

      // Execute: Process batch through complete pipeline with mocked AI
      const result = await emailProcessor.processBatch({ maxEmails: 10 });

      // Validate: FR-001 - Direct Gmail API integration (all emails processed)
      expect(result.totalProcessed).toBe(2);
      expect(result.processingDurationMs).toBeGreaterThan(0);
      expect(result.averageEmailDurationMs).toBeGreaterThan(0);

      // Validate: With mocked AI, all emails should succeed
      expect(result.successCount).toBe(2);
      expect(result.errorCount).toBe(0);

      // Validate: FR-008 - Batch persistence and FR-002 - Classification structure
      const savedResults = persistence.getSavedResults();
      expect(savedResults.size).toBe(2);

      // Validate: FR-002 - Classification engine preserves results structure
      const firstSaved = Array.from(savedResults.values())[0];
      expect(firstSaved).toBeDefined();
      expect(firstSaved.selectedLabels).toBeDefined();
      expect(firstSaved.candidateScores).toBeDefined();
      expect(firstSaved.selectionSummary).toBeDefined();
    });

    test('should handle partial failures gracefully (FR-005 error resilience)', async () => {
      // Setup: Mix of valid and problematic emails
      const mockEmails = [
        createRealisticEmail('msg-valid', 'Normal email subject', 'sender@example.com'),
        // Email with minimal data that might cause classification issues
        createMinimalEmail('msg-problematic'),
        createRealisticEmail('msg-valid-2', 'Another normal email', 'another@example.com'),
      ];

      gmailClient.setMockEmails(mockEmails);

      // Execute: Process batch - with mocked AI, should all succeed
      const result = await emailProcessor.processBatch({ maxEmails: 10 });

      // Validate: All emails processed successfully with mocked AI
      expect(result.totalProcessed).toBe(3);
      expect(result.processingDurationMs).toBeGreaterThan(0);
      expect(result.successCount).toBe(3);
      expect(result.errorCount).toBe(0);
    });

    test('should return accurate metrics for empty batch', async () => {
      // Setup: No emails to process
      gmailClient.setMockEmails([]);

      // Execute
      const result = await emailProcessor.processBatch({ maxEmails: 10 });

      // Validate: Metrics reflect empty batch correctly
      expect(result.totalProcessed).toBe(0);
      expect(result.successCount).toBe(0);
      expect(result.errorCount).toBe(0);
      expect(result.averageEmailDurationMs).toBe(0);
      expect(result.errors).toHaveLength(0);

      // Validate: No persistence calls for empty batch
      expect(persistence.getSavedResults().size).toBe(0);
    });

    test('should propagate fatal Gmail API failures (FR-001)', async () => {
      // Setup: Gmail API failure
      gmailClient.setShouldFailFetch(true);

      // Execute & Validate: Fatal errors propagate
      await expect(emailProcessor.processBatch({ maxEmails: 10 })).rejects.toThrow(
        'Batch processing failed: Gmail API connection failed'
      );
    });

    test('should propagate fatal persistence failures (FR-008)', async () => {
      // Setup: Valid emails but database failure
      const mockEmails = [createRealisticEmail('msg-001', 'Test Subject', 'sender@example.com')];

      gmailClient.setMockEmails(mockEmails);
      persistence.setShouldFailSave(true);

      // Execute: With mocked AI, classification succeeds but persistence fails
      await expect(emailProcessor.processBatch({ maxEmails: 10 })).rejects.toThrow('Database connection failed');
    });
  });

  describe('Single Email Processing Integration (FR-001)', () => {
    test('should process single email through complete workflow', async () => {
      // Setup
      const mockEmail = createRealisticEmail(
        'msg-single',
        'Invoice from Stripe for your subscription',
        'billing@stripe.com'
      );

      gmailClient.setMockEmails([mockEmail]);

      // Execute with mocked AI
      const result = await emailProcessor.processSingle('msg-single');

      // Validate: FR-001 - Single email processing completes successfully
      expect(result.emailId).toBe('msg-single');
      expect(result.processingDurationMs).toBeGreaterThan(0);
      expect(result.success).toBe(true);

      // Validate: Successful classification
      expect(result.classificationResult).toBeDefined();
      expect(result.classificationResult?.selectedLabels).toBeDefined();

      // Validate: Persistence saved result
      const savedResults = persistence.getSavedResults();
      expect(savedResults.has('msg-single')).toBe(true);
    });

    test('should handle single email not found error', async () => {
      // Setup: Empty email list
      gmailClient.setMockEmails([]);

      // Execute
      const result = await emailProcessor.processSingle('msg-nonexistent');

      // Validate: Error result structure
      expect(result.success).toBe(false);
      expect(result.emailId).toBe('msg-nonexistent');
      expect(result.error).toBeDefined();
      expect(result.error?.message).toContain('Email not found');

      // Validate: No persistence for failed email
      expect(persistence.getSavedResults().size).toBe(0);
    });

    test('should handle Gmail API failure for single email', async () => {
      // Setup: Gmail API failure
      gmailClient.setShouldFailFetch(true);

      // Execute
      const result = await emailProcessor.processSingle('msg-any');

      // Validate: Error captured in result
      expect(result.success).toBe(false);
      expect(result.error?.message).toContain('Gmail API connection failed');
    });
  });

  describe('Performance Metrics Integration (FR-005)', () => {
    test('should track accurate timing for batch processing', async () => {
      // Setup: Multiple emails for timing validation
      const mockEmails = Array.from({ length: 5 }, (_, i) =>
        createRealisticEmail(`msg-${i}`, `Subject ${i}`, 'sender@example.com')
      );

      gmailClient.setMockEmails(mockEmails);

      // Execute
      const startTime = Date.now();
      const result = await emailProcessor.processBatch({ maxEmails: 10 });
      const actualDuration = Date.now() - startTime;

      // Validate: Reported metrics match actual timing (within tolerance)
      expect(result.processingDurationMs).toBeGreaterThan(0);
      expect(result.processingDurationMs).toBeLessThanOrEqual(actualDuration + 50); // 50ms tolerance

      // Validate: Average calculation
      const expectedAverage = result.processingDurationMs / result.totalProcessed;
      expect(result.averageEmailDurationMs).toBeCloseTo(expectedAverage, 1);
    });

    test('should preserve individual email processing duration', async () => {
      // Setup
      const mockEmail = createRealisticEmail('msg-perf', 'Performance test email', 'sender@example.com');
      gmailClient.setMockEmails([mockEmail]);

      // Execute
      const result = await emailProcessor.processSingle('msg-perf');

      // Validate: Processing duration captured
      expect(result.processingDurationMs).toBeGreaterThan(0);

      // Validate: Classification result has duration (if classification succeeded)
      if (result.success && result.classificationResult) {
        expect(result.classificationResult.processingDurationMs).toBeGreaterThan(0);
      }
    });
  });

  describe('Batch Options Integration (FR-008)', () => {
    test('should respect maxEmails option', async () => {
      // Setup: More emails than limit
      const mockEmails = Array.from({ length: 20 }, (_, i) =>
        createRealisticEmail(`msg-${i}`, `Subject ${i}`, 'sender@example.com')
      );

      gmailClient.setMockEmails(mockEmails);

      // Execute with limit
      const result = await emailProcessor.processBatch({ maxEmails: 5 });

      // Validate: Only maxEmails processed
      // Note: This validates EmailProcessor passes options to GmailClient
      expect(result.totalProcessed).toBeLessThanOrEqual(mockEmails.length);
    });
  });
});

/**
 * Create realistic email for integration testing
 */
function createRealisticEmail(id: string, subject: string, fromEmail: string): EmailMessage {
  return {
    id,
    threadId: `thread-${id}`,
    gmailLabels: ['INBOX', 'UNREAD'],
    payload: {
      mimeType: 'text/html',
      headers: [
        { name: 'Subject', value: subject },
        { name: 'From', value: `${fromEmail.split('@')[0]} <${fromEmail}>` },
        { name: 'To', value: 'user@example.com' },
        { name: 'Date', value: new Date().toUTCString() },
      ],
      body: {
        data: Buffer.from(`<html><body><p>Email body for ${subject}</p></body></html>`).toString('base64'),
      },
    },
    subject,
    from: {
      email: fromEmail,
      name: fromEmail.split('@')[0],
      raw: `${fromEmail.split('@')[0]} <${fromEmail}>`,
    },
    to: [
      {
        email: 'user@example.com',
        name: 'User',
        raw: 'User <user@example.com>',
      },
    ],
    date: new Date(),
    bodyPlain: `Email body for ${subject}`,
    bodyHtml: `<html><body><p>Email body for ${subject}</p></body></html>`,
    isProcessed: false,
    processingPriority: 50,
  };
}

/**
 * Create minimal email (might trigger edge cases in classification)
 */
function createMinimalEmail(id: string): EmailMessage {
  return {
    id,
    threadId: `thread-${id}`,
    gmailLabels: ['INBOX'],
    payload: {
      mimeType: 'text/plain',
      headers: [
        { name: 'Subject', value: '' },
        { name: 'From', value: 'unknown@example.com' },
      ],
      body: {
        data: Buffer.from('').toString('base64'),
      },
    },
    subject: '',
    from: {
      email: 'unknown@example.com',
      name: '',
      raw: 'unknown@example.com',
    },
    to: [],
    date: new Date(),
    bodyPlain: '',
    isProcessed: false,
    processingPriority: 50,
  };
}

