import type { AIClient, ChatCompletionParams, ChatCompletionResponse } from '@gmail-automation/classification-engine';

/**
 * Mock AI client for integration tests
 *
 * INTENTIONAL SIMPLICITY:
 * - Returns deterministic, happy-path responses only
 * - No failure scenarios (rate limits, malformed JSON, network errors)
 * - Simple keyword-based prompt detection
 * - Same canned response structure for all matching prompts
 *
 * WHEN TO ENHANCE:
 * - Add failure scenarios when testing retry/error handling becomes necessary
 * - Add response customization (setNextResponse) when testing specific edge cases
 * - Add prompt-specific responses when default responses cause test failures
 * - Add usage metrics tracking when testing token consumption logic
 *
 * WHAT NOT TO DO:
 * - Don't make this a full OpenAI SDK simulator
 * - Don't add complexity until tests actually need it
 * - Don't test OpenAI's behavior - test OUR behavior with deterministic responses
 *
 * Provides deterministic responses without external API calls.
 * Intelligently returns different responses based on prompt content.
 */
export class MockAIClient implements AIClient {
  private callCount = 0;

  async chatComplete(params: ChatCompletionParams): Promise<ChatCompletionResponse> {
    this.callCount++;

    // Determine which response to return based on prompt content
    const userMessage = params.messages.find((m) => m.role === 'user')?.content || '';

    // Feature extraction prompt detection
    if (
      userMessage.includes('feature') ||
      userMessage.includes('semantic') ||
      userMessage.includes('extract') ||
      userMessage.includes('enhancement')
    ) {
      return this.createFeatureExtractionResponse();
    }

    // Classification prompt detection
    return this.createClassificationResponse();
  }

  /**
   * Mock feature extraction response
   * Matches FeatureExtractionData interface exactly
   */
  private createFeatureExtractionResponse(): ChatCompletionResponse {
    const responseData = {
      semanticIntent: {
        primaryPurpose: 'notification' as const,
        actionRequired: 'view' as const,
        urgencyLevel: 'low' as const,
      },
      categoryEnhancements: {
        bills_receipts: {
          applies: true,
          confidenceBoost: 0.15,
          evidence: {
            quotedPhrases: ['Invoice', 'payment due'],
            keywords: ['invoice', 'receipt', 'transaction'],
            reasoning: 'Mock: Invoice-like content detected',
          },
        },
        shopping_commerce: {
          applies: true,
          confidenceBoost: 0.05,
          evidence: {
            quotedPhrases: ['order', 'shipped'],
            keywords: ['order', 'delivery', 'shipping'],
            reasoning: 'Mock: Commercial transaction detected',
          },
        },
      },
    };

    return {
      choices: [
        {
          message: { content: JSON.stringify(responseData), role: 'assistant' },
          finish_reason: 'stop',
          index: 0,
        },
      ],
      usage: {
        total_tokens: 150,
        prompt_tokens: 100,
        completion_tokens: 50,
      },
      model: 'gpt-4o-mini-mock',
      id: `mock-completion-${this.callCount}`,
      created: Date.now(),
    };
  }

  /**
   * Mock classification response
   * Matches FinalClassification interface exactly
   */
  private createClassificationResponse(): ChatCompletionResponse {
    const responseData = {
      primaryCategory: 'bills_receipts',
      secondaryCategories: ['shopping_commerce'],
      confidence: 0.85,
      reasoning: 'Mock AI classification: Invoice detected based on transactional content',
      categoryScores: {
        bills_receipts: 0.85,
        shopping_commerce: 0.65,
        personal: 0.2,
      },
    };

    return {
      choices: [
        {
          message: { content: JSON.stringify(responseData), role: 'assistant' },
          finish_reason: 'stop',
          index: 0,
        },
      ],
      usage: {
        total_tokens: 150,
        prompt_tokens: 100,
        completion_tokens: 50,
      },
      model: 'gpt-4o-mini-mock',
      id: `mock-completion-${this.callCount}`,
      created: Date.now(),
    };
  }

  /**
   * Reset mock state (call in beforeEach)
   */
  reset(): void {
    this.callCount = 0;
  }

  /**
   * Get number of AI calls made (for test assertions)
   */
  getCallCount(): number {
    return this.callCount;
  }
}

